module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // FunctionalModel architectural state variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    // SSOT memory.instances evidence aliases mapped to architectural state.
    logic [COUNT_WIDTH-1:0] count_state_ff;
    logic                   wrapped_state_ff;
    logic                   valid_state_ff;

    // FSM control states declared in SSOT fsm.control.
    localparam [1:0] RESET  = 2'd0;
    localparam [1:0] CLEAR  = 2'd1;
    localparam [1:0] UPDATE = 2'd2;
    localparam [1:0] IDLE   = 2'd3;

    logic [1:0] fsm_state_q;
    logic [1:0] fsm_state_d;

    // Arithmetic helpers for FM_UPDATE: zero-extend step, perform add, truncate modulo 256.
    logic [COUNT_WIDTH-1:0] step_ext;
    logic [COUNT_WIDTH:0]   sum_ext;

    // Named output-rule signals used as real output drivers.
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    assign count_state_ff   = count_q;
    assign wrapped_state_ff = wrapped_q;
    assign valid_state_ff   = valid_q;

    assign step_ext = {{(COUNT_WIDTH-STEP_WIDTH){1'b0}}, step};
    assign sum_ext  = {1'b0, count_state_ff} + {1'b0, step_ext};

    // SSOT transition graph implementation: RESET->IDLE, IDLE->{CLEAR,UPDATE,IDLE},
    // UPDATE->IDLE and CLEAR->IDLE on the following cycle.
    always @(*) begin
        fsm_state_d = fsm_state_q;
        case (fsm_state_q)
            RESET: begin
                fsm_state_d = IDLE;
            end
            IDLE: begin
                if (clear) begin
                    fsm_state_d = CLEAR;
                end else if (enable) begin
                    fsm_state_d = UPDATE;
                end else begin
                    fsm_state_d = IDLE;
                end
            end
            UPDATE: begin
                fsm_state_d = IDLE;
            end
            CLEAR: begin
                fsm_state_d = IDLE;
            end
            default: begin
                fsm_state_d = IDLE;
            end
        endcase
    end

    // latency=1 contract: clear/enable/step sampled and committed on this same rising edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            fsm_state_q <= RESET;
            count_q     <= {COUNT_WIDTH{1'b0}};
            wrapped_q   <= 1'b0;
            valid_q     <= 1'b0;
        end else begin
            fsm_state_q <= fsm_state_d;

            // clear_enable_priority: clear branch is evaluated before enable branch.
            if (clear) begin
                count_q   <= {COUNT_WIDTH{1'b0}};
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end else if (enable) begin
                count_q   <= sum_ext[COUNT_WIDTH-1:0];
                wrapped_q <= sum_ext[COUNT_WIDTH];
                valid_q   <= 1'b1;
            end else begin
                count_q   <= count_q;
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end
        end
    end

    // Output-rule mapping for FM_CLEAR/FM_UPDATE/FM_IDLE observables.
    assign out_count   = count_q;
    assign out_wrapped = wrapped_q;
    assign out_valid   = valid_q;

    assign count   = out_count;
    assign wrapped = out_wrapped;
    assign valid   = out_valid;

endmodule

